formula.dax:
CALCULATE(
    DIVIDE(
        [REGLEMENT NON EFFECTIF (ECHEANCE)],
        [ECHEANCE ATTENDUE LC]
    ),
    FILTER(
        'MAIN VINTAGE ECHEANCE',
        'MAIN VINTAGE ECHEANCE'[NextScheduleDate] <= [DATE UPDATE]
    )
)

CALCULATE(
    DIVIDE(
        [Echeance attendu effectif (MAIN)BIS],
        [ECHEANCE ATTENDUE LC]
    ),
    FILTER(
        'MAIN VINTAGE ECHEANCE',
        'MAIN VINTAGE ECHEANCE'[NextScheduleDate] <= [DATE UPDATE]
    )
)

CALCULATE(
    DIVIDE(
        [REGLEMENT EFFECTIF (MAIN)],
        [ENCOURS ECHEANCE LC]
    ),
    FILTER(
        'MAIN VINTAGE ECHEANCE',
        'MAIN VINTAGE ECHEANCE'[NextScheduleDate] <= [DATE UPDATE]
    )
)
